#!/usr/bin/env Rscript
# This is an R script for visualizing internal cross-validation results in FAPROTAX2 to compare the performance of
# the candidate HSP algorithms.
#
#
#
# Rob Porch
# Updated 2026 April 12
#

#######################
# Load necessary packages

library(tidyverse)
library(readr)
library(data.table)
library(purrr)
library(patchwork)
library(showtext)
library(sysfonts)
library(optparse)
#######################

# Parse command-line arguments
option_list <- list(
  make_option("--in_cv_results_dir", type="character", default="", help="Path to folder containing CV results files generated by FAPROTAX2 in 'cv' mode."),
  make_option("--in_config", type="character", default="", help="Path to default config file of optimized HSP algorithms based on balanced accuracy."),
  make_option(c("-o", "--out_optimal_figure"), type="character", default="", help="Path to store output figure of optimal CV results."),
  make_option("--out_HSPs_figure", type="character", default="", help="Path to store output figure of all HSPs CV results.")
)

opt <- parse_args(OptionParser(option_list=option_list))


####################
# MAIN SCRIPT BODY
default_config <- data.table::fread(file=opt$in_config, header=TRUE)

files <- list.files(path=opt$in_cv_results_dir, pattern="\\.urs_config\\.tsv$")
dfs <- list()

for (f in files) {
  hsp_name <- sub("\\.urs_config\\.tsv$", "", f)
  
  df <- fread(paste0(opt$in_cv_results_dir, "/", f), sep = "\t", fill = TRUE)
  df <- as.data.frame(df)
  
  names(df)[names(df) == "function"] <- "func"
  
  df$HSP <- hsp_name
  
  df$ratio <- df$test_MDNR / df$phylogenetic_conservatism
  
  dfs[[f]] <- df
}

full_data <- bind_rows(dfs)

full_data$HSP <- gsub("_", " ", full_data$HSP)


HSP_color_codes <- c("Markov" = "#469c75", "binomial" = "#264653", "nearest neighbor" = "#e76f51", "max parsimony" = "#f4a261",
					"empirical probabilities" = "#2a9d8f")




#### Visualize
##############

# Optimal HSPs overall plots
BA_optimal_plot <- ggplot(default_config, aes(x = test_MDNR/phylogenetic_conservatism, y = balanced_accuracy)) +
	geom_point(size = 2, alpha = 0.6, color="#265db5") + ylim(0,1) +
	scale_x_log10() +
	labs(
		x = "MDNR/conservatism",
		y = "Mean balanced accuracy"
	) + theme_classic() +
	theme(
		axis.line=element_blank(),
		panel.border=element_rect(fill=NA, color="black", linewidth=1),
		axis.title=element_text(size=14),
		axis.text=element_text(size=9),
		legend.position="none"
	)
	
TPR_optimal_plot <- ggplot(default_config, aes(x = test_MDNR/phylogenetic_conservatism, y = true_positive_rate)) +
	geom_point(size = 2, alpha = 0.6, color="#265db5") + ylim(0,1) +
	scale_x_log10() +
	labs(
		x = "MDNR/conservatism",
		y = "Mean true positive rate"
	) + theme_classic() +
	theme(
		axis.line=element_blank(),
		panel.border=element_rect(fill=NA, color="black", linewidth=1),
		axis.title=element_text(size=14),
		axis.text=element_text(size=9),
		legend.position="none"
	)

TNR_optimal_plot <- ggplot(default_config, aes(x = test_MDNR/phylogenetic_conservatism, y = true_negative_rate)) +
	geom_point(size = 2, alpha = 0.6, color = "#265db5") + ylim(0,1) +
	scale_x_log10() +
	labs(
		x = "MDNR/conservatism",
		y = "Mean true negative rate"
	) + theme_classic() +
	theme(
		axis.line=element_blank(),
		panel.border=element_rect(fill=NA, color="black", linewidth=1),
		axis.title=element_text(size=14),
		axis.text=element_text(size=9),
		legend.position="none"
	)


##########
# All HSPs comparison plots

BA_scatterplot <- ggplot(full_data, aes(x = ratio, y = balanced_accuracy, color = HSP, group = HSP)) +
	geom_point(size = 2, alpha = 0.6) + ylim(0,1) +
	scale_x_log10() + facet_wrap(~HSP, ncol=5) +
	scale_color_manual(values=HSP_color_codes) +
	labs(
		x = "MDNR/conservatism",
		y = "Mean balanced accuracy",
		color = "HSP algorithm",
		shape = "HSP algorithm"
	) + theme_classic() +
	theme(
		axis.line=element_blank(),
		panel.border=element_rect(fill=NA, color="black", linewidth=1),
		axis.title=element_text(size=11),
		axis.text=element_text(size=9),
		strip.background = element_blank(),
		legend.position="none"
	)
	
TPR_scatterplot <- ggplot(full_data, aes(x = ratio, y = true_positive_rate, color = HSP, group = HSP)) +
	geom_point(size = 2, alpha = 0.6) + ylim(0,1) +
	scale_x_log10() + facet_wrap(~HSP, ncol=5) +
	scale_color_manual(values=HSP_color_codes) +
	labs(
		x = "MDNR/conservatism",
		y = "Mean true positive rate",
		color = "HSP algorithm",
		shape = "HSP algorithm"
	) + theme_classic() +
	theme(
		axis.line=element_blank(),
		panel.border=element_rect(fill=NA, color="black", linewidth=1),
		axis.title=element_text(size=11),
		axis.text=element_text(size=9),
		strip.background = element_blank(),
		legend.position="none"
	)

TNR_scatterplot <- ggplot(full_data, aes(x = ratio, y = true_negative_rate, color = HSP, group = HSP)) +
	geom_point(size = 2, alpha = 0.6) + ylim(0,1) +
	scale_x_log10() + facet_wrap(~HSP, ncol=5) +
	scale_color_manual(values=HSP_color_codes) +
	labs(
		x = "MDNR/conservatism",
		y = "Mean true negative rate",
		color = "HSP algorithm",
		shape = "HSP algorithm"
	) + theme_classic() +
	theme(
		axis.line=element_blank(),
		panel.border=element_rect(fill=NA, color="black", linewidth=1),
		axis.title=element_text(size=11),
		axis.text=element_text(size=9),
		strip.background = element_blank(),
		legend.position="none"
	)

full_optimal_HSP_figure <- BA_optimal_plot + TPR_optimal_plot + TNR_optimal_plot &
  theme(
    plot.margin = margin(t = 15, r = 10, b = 10, l = 10)
  )

full_HSPs_figure <- BA_scatterplot / TPR_scatterplot / TNR_scatterplot
	
ggsave(opt$out_optimal_figure, full_optimal_HSP_figure, width=9, height=4)
ggsave(opt$out_HSPs_figure, full_HSPs_figure, width=10, height=8)